UserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"f550f8b5-902d-45b3-82be-37034f3d7c7c"},{"version":"CommandV1","origId":1083584440950392,"guid":"d319cdd5-68c4-4870-aff1-f2e812729094","subtype":"command","commandType":"auto","position":9.0,"command":"%md\n### Using Spark DataFrame","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"9633b62b-2c30-41e1-a685-7319556b0dce"},{"version":"CommandV1","origId":1083584440950393,"guid":"065c6dce-da04-457a-b382-ec899d7b2393","subtype":"command","commandType":"auto","position":10.0,"command":"%python\n# Create a Spark DataFrame\ndf = spark.range(1, 4)\n\n# Execute function as a Spark vectorized UDF\ndf.select(\"id\", cubed_udf(col(\"id\"))).show()","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"374b2834-3695-4abe-a131-e595c75216d1"},{"version":"CommandV1","origId":1083584440950394,"guid":"a5e91e0f-cba7-4ffc-9585-9f2ca2cd1989","subtype":"command","commandType":"auto","position":11.0,"command":"%md\n## Higher Order Functions in DataFrames and Spark SQL\n\nBecause complex data types are an amalgamation of simple data types, it is tempting to manipulate complex data types directly. As noted in the post *Introducing New Built-in and Higher-Order Functions for Complex Data Types in Apache Spark 2.4* there are typically two solutions for the manipulation of complex data types.\n1. Exploding the nested structure into individual rows, applying some function, and then re-creating the nested structure as noted in the code snippet below (see Option 1)  \n1. Building a User Defined Function (UDF)","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"33643ccc-4f1c-4054-8e0e-76934d5e2572"},{"version":"CommandV1","origId":1083584440950395,"guid":"58792bcc-0860-4742-bf5f-23b82b5563ec","subtype":"command","commandType":"auto","position":12.0,"command":"import org.apache.spark.sql._\nimport org.apache.spark.sql.types._\n\n// Create an array dataset\nval arrayData = Seq(\n  Row(1, List(1, 2, 3)),\n  Row(2, List(2, 3, 4)),\n  Row(3, List(3, 4, 5))\n)\n\n// Create schema\nval arraySchema = new StructType()\n  .add(\"id\", IntegerType)\n  .add(\"values\", ArrayType(IntegerType))\n\n// Create DataFrame\nval df = spark.createDataFrame(spark.sparkContext.parallelize(arrayData), arraySchema)\ndf.createOrReplaceTempView(\"table\")\ndf.printSchema()\ndf.show()","commandVersion":5,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"bc84cf00-92dd-422a-87c8-edf375bc4cb1"},{"version":"CommandV1","origId":1083584440950396,"guid":"084a7a55-4c9a-4f8f-b7ad-8f2c1401c52a","subtype":"command","commandType":"auto","position":13.0,"command":"%md\n#### Option 1: Explode and Collect\nIn this nested SQL statement, we first `explode(values)` which creates a new row (with the id) for each element (`value`) within values.  ","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"46a12f4e-9b36-4850-a957-6fb0e980973e"},{"version":"CommandV1","origId":1083584440950397,"guid":"422c588e-7fe8-4370-a81c-c0036092d1ea","subtype":"command","commandType":"auto","position":14.0,"command":"spark.sql(\"\"\"\nSELECT id, collect_list(value + 1) AS newValues\n  FROM  (SELECT id, explode(values) AS value\n        FROM table) x\n GROUP BY id\n\"\"\").show()","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"acb7058f-6149-4eb5-ae62-0e33886c628a"},{"version":"CommandV1","origId":1083584440950398,"guid":"599e7c4f-6120-4833-be24-d44eb4604d00","subtype":"command","commandType":"auto","position":15.0,"command":"%md\n#### Option 2: User Defined Function\nTo perform the same task (adding a value of 1 to each element in `values`), we can also create a user defined function (UDF) that uses map to iterate through each element (`value`) to perform the addition operation.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"8ca58f0a-e332-49ca-81d2-7474ce10648e"},{"version":"CommandV1","origId":1083584440950399,"guid":"e1312d9d-500a-429a-a6ed-2f521e196ddb","subtype":"command","commandType":"auto","position":16.0,"command":"// Create UDF\ndef addOne(values: Seq[Int]): Seq[Int] = {\n    values.map(value => value + 1)\n}\n\n// Register UDF\nval plusOneInt = spark.udf.register(\"plusOneInt\", addOne(_: Seq[Int]): Seq[Int])\n\n// Query data\nspark.sql(\"SELECT id, plusOneInt(values) AS values FROM table\").show()","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xCol